const amqp = require('amqplib');
const { Client } = require('pg'); // Assuming PostgreSQL for database queries
const express = require('express');

const app = express();
const QUEUE_NAME = 'your_queue_name';
const RABBITMQ_URL = 'amqp://localhost';
const DB_CONFIG = {
    user: 'your_db_user',
    host: 'localhost',
    database: 'your_db_name',
    password: 'your_db_password',
    port: 5432,
};

const client = new Client(DB_CONFIG);
client.connect();

async function processMessage(msg) {
    try {
        const messageContent = JSON.parse(msg.content.toString());
        const { type, payload } = messageContent;

        switch (type) {
            case 'CREATE':
                await createRecord(payload);
                break;
            case 'UPDATE':
                await updateRecord(payload);
                break;
            case 'DELETE':
                await deleteRecord(payload);
                break;
            default:
                console.error('Unknown message type:', type);
        }
    } catch (error) {
        console.error('Error processing message:', error);
    }
}

async function createRecord(payload) {
    const query = 'INSERT INTO your_table_name(column1, column2) VALUES($1, $2)';
    const values = [payload.field1, payload.field2];
    await client.query(query, values);
}

async function updateRecord(payload) {
    const query = 'UPDATE your_table_name SET column1 = $1 WHERE id = $2';
    const values = [payload.field1, payload.id];
    await client.query(query, values);
}

async function deleteRecord(payload) {
    const query = 'DELETE FROM your_table_name WHERE id = $1';
    const values = [payload.id];
    await client.query(query, values);
}

async function startConsuming() {
    const connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();
    await channel.assertQueue(QUEUE_NAME, { durable: true });

    channel.consume(QUEUE_NAME, async (msg) => {
        if (msg !== null) {
            await processMessage(msg);
            channel.ack(msg);
        }
    }, { noAck: false });
}

app.listen(3000, () => {
    console.log('Microservice is running on port 3000');
    startConsuming().catch(console.error);
});